def within_tol(base: object, other: object, rel_tol: float | None, abs_tol: float | None, default_rel: float = 0.01) -&gt; bool:
    """Check if two values are within tolerance."""
    base_num = numeric_value(base)
    other_num = numeric_value(other)
    if base_num is None or other_num is None:
