    if rel_tol is None and abs_tol is None:
        rel = default_rel
        abs_t = 0.0
    else:
        rel = rel_tol or 0.0
        abs_t = abs_tol or 0.0
    scale = max(abs(base_num), abs(other_num), 1.0)
    tol = max(abs_t, rel * scale)
